  .ad { width: 1080px; height: 1920px; overflow: hidden; position: relative; }

  /* Layer 1 — slow ken-burns on bottle background (1.00 → 1.06 over 9s) */
  .bg {
    position: absolute; inset: 0;
    background: url('mppj6lpq-inku-image-[REDACTED:phone].png') no-repeat center/cover;
    transform-origin: 50% 55%;
    animation: kenburns 9s ease-in-out infinite;
  }
  @keyframes kenburns {
    0%   { transform: scale(1.00); }
    100% { transform: scale(1.06); }
  }

  /* Scrims — fade in subtly with the copy reveal */
  .top-scrim { position: absolute; top: 0; left: 0; right: 0; height: 420px;
               background: linear-gradient(180deg, rgba(253,254,255,0.96) 0%, rgba(253,254,255,0.92) 60%, rgba(253,254,255,0) 100%);
